import { Link, useLocation } from "react-router-dom";

export default function Navbar() {
  const location = useLocation();

  const links = [
    { path: "/AfficherUtilisateur", name: "AfficherUtilisateur" },
    { path: "/afficher", name: "afficher" },
    { path: "/taches", name: "Tâches" },
    { path: "/chat", name: "Chat" },
    { path: "/rapports", name: "Rapports" },
  ];

  return (
    <nav style={styles.nav}>
      <h2 style={styles.logo}>Claud</h2>

      <div style={styles.links}>
        {links.map((link) => (
          <Link
            key={link.path}
            to={link.path}
            style={{
              ...styles.link,
              ...(location.pathname === link.path ? styles.active : {}),
            }}
          >
            {link.name}
          </Link>
        ))}
      </div>
    </nav>
  );
}

const styles = {
  nav: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    padding: "15px 30px",
    background: "#1e293b",
    color: "white",
  },
  logo: {
    margin: 0,
  },
  links: {
    display: "flex",
    gap: "20px",
  },
  link: {
    textDecoration: "none",
    color: "white",
    fontWeight: "500",
  },
  active: {
    borderBottom: "2px solid #38bdf8",
  },
};
